#requires -Version 5.1
<# Created by Dewald Pretorius. Validates PowerShell module manifests and syntax without importing or executing functions. #>
[CmdletBinding()]param([string]$ModulePath=$PSScriptRoot,[string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'Enterprise_Module_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{$scripts=@(Get-ChildItem $ModulePath -Recurse -Include '*.ps1','*.psm1'|Where-Object FullName -ne $PSCommandPath);$results=@();foreach($f in $scripts){$tokens=$null;$errors=$null;[void][Management.Automation.Language.Parser]::ParseFile($f.FullName,[ref]$tokens,[ref]$errors);$results+=[pscustomobject]@{File=$f.FullName;SyntaxErrors=$errors.Count;ErrorText=($errors.Message-join'; ')}};$manifests=@(Get-ChildItem $ModulePath -Recurse -Filter '*.psd1');$manifestResults=@();foreach($m in $manifests){try{$data=Test-ModuleManifest $m.FullName -ErrorAction Stop;$manifestResults+=[pscustomobject]@{File=$m.FullName;Valid=$true;Version=$data.Version;Error=$null}}catch{$manifestResults+=[pscustomobject]@{File=$m.FullName;Valid=$false;Version=$null;Error=$_.Exception.Message}}};[ordered]@{Generated=(Get-Date);Scripts=$results;Manifests=$manifestResults;SyntaxErrorFileCount=@($results|Where-Object SyntaxErrors -gt0).Count;InvalidManifestCount=@($manifestResults|Where-Object{-not$_.Valid}).Count}|ConvertTo-Json -Depth 7|Set-Content (Join-Path $OutputPath "module_validation_$s.json");if(@($results|Where-Object SyntaxErrors -gt0).Count-or@($manifestResults|Where-Object{-not$_.Valid}).Count){exit 1};exit 0}catch{Write-Error $_;exit 5}
